  ('elementary-8b44517b-moex-00547', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者不屬於「法律保留原則」之內涵？', '["行政行為或其他一切行政活動，均不得與法律相牴觸", "憲法要求特定事項須由立法機關以法律加以規定", "何種事項應以法律直接規範或得委由命令予以規定，視規範對象、內容或法益本身及其所受限制 之輕重而有不同", "有組織法之授權不等於即有作用法之授權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00548', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於聯邦國與單一國之選擇，下列敘述何者錯誤？', '["單一國之地方政府不具水平權力分立之機關", "兩者在國家統治權力分配上有所不同", "聯邦國之成員州或邦得有獨立之司法系統", "聯邦國之成員州或邦享有憲法保障之自主權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00549', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依行政執行法規定，行政執行，應以適當之方法為之，不得逾達成執行目的之必要限度。此為下列 何原則之實現？', '["法律保留原則", "明確性原則", "信賴保護原則", "比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00550', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '若交通監理機關依職權要求，換發行車執照前，須先繳清違規罰鍰，否則不得辦理。此可能涉及下 列何原則？', '["比例原則", "法律優位原則", "不當聯結禁止原則", "信賴保護原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00551', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '行政機關為求裁量判斷標準一致，往往會以行政規則方式訂頒裁量基準。行政機關即應依該裁量基 準為行政行為，此為下列何種原則之表現？', '["行政自我拘束原則", "比例原則", "法律保留原則", "不當聯結禁止原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00552', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依司法院釋字第709號意旨，下列何者非該解釋所強調之都市更新應踐行的正當行政程序？', '["主管機關應將計畫相關資訊，對更新單元內申請人以外之其他土地及合法建築物所有權人分別為 送達", "應以公開方式舉辦聽證，使利害關係人得到場以言詞為意見之陳述及論辯", "應斟酌全部聽證紀錄，說明採納及不採納之理由作成核定", "在應舉辦聽證的前提下，利害關係人適時陳述意見與知悉相關資訊之機會即可省略之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00553', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者非屬行政秩序罰？', '["吊扣證照", "罰金", "沒入", "公布照片"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00554', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於依行政罰法不予處罰之事由，下列敘述何者錯誤？', '["依法令之行為，不予處罰", "未滿18歲之未成年人之行為，不予處罰", "違反行政法上義務之行為非出於故意或過失者，不予處罰", "對於現在不法之侵害，而出於防衛自己或他人權利之行為，不予處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00555', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列有關懲戒之敘述，何者錯誤？', '["懲戒處分係由懲戒法庭以裁判之形式作成", "監察院對公務員提出彈劾後，得將其移送懲戒", "對九職等以下之公務員，公務員所屬機關得逕為記過及申誡之懲戒處分", "撤職，係指撤公務員之現職，並於1年以上，5年以下之期間停止任用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00556', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '對政務人員不得為下列何種懲戒處分？', '["免除職務", "記過", "剝奪退職金", "申誡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
